const EDEXCEL_WRITTEN_M5_M7 = {

  'M5': {
    name: 'Variable Acceleration',
    green: [
      { q: 'A particle moves so that its displacement is \\(s = 3t^2 - 2t + 1\\) metres at time \\(t\\) seconds. Find the velocity at time \\(t\\).', marks: 2, tier: 'green', modelAnswer: 'Differentiate: \\(v = \\dfrac{ds}{dt} = 6t - 2\\) m/s.' },
      { q: 'A particle moves so that \\(s = t^3 - 4t\\) metres. Find the velocity when \\(t = 3\\).', marks: 3, tier: 'green', modelAnswer: 'Differentiate: \\(v = 3t^2 - 4\\). At \\(t = 3\\): \\(v = 3(9) - 4 = 27 - 4 = 23\\) m/s.' },
      { q: 'A particle has velocity \\(v = 4t^3 - 6t\\) m/s. Find the acceleration at time \\(t\\).', marks: 2, tier: 'green', modelAnswer: 'Differentiate: \\(a = \\dfrac{dv}{dt} = 12t^2 - 6\\) m/s².' },
      { q: 'A particle has velocity \\(v = 6t^2 - 2t + 5\\) m/s. Find the acceleration when \\(t = 2\\).', marks: 3, tier: 'green', modelAnswer: 'Differentiate: \\(a = 12t - 2\\). At \\(t = 2\\): \\(a = 12(2) - 2 = 24 - 2 = 22\\) m/s².' },
      { q: 'A particle moves with velocity \\(v = t^2 - 5t + 6\\) m/s. Find the times when the particle is at rest.', marks: 3, tier: 'green', modelAnswer: 'Set \\(v = 0\\): \\(t^2 - 5t + 6 = 0\\). Factorise: \\((t-2)(t-3) = 0\\). So \\(t = 2\\) s or \\(t = 3\\) s.' },
      { q: 'A particle has displacement \\(s = 2t^3 - 9t^2 + 12t\\) metres. Find when the particle is at rest.', marks: 3, tier: 'green', modelAnswer: 'Differentiate: \\(v = 6t^2 - 18t + 12\\). Set \\(v = 0\\): \\(6(t^2 - 3t + 2) = 0\\), so \\(6(t-1)(t-2) = 0\\). Particle is at rest at \\(t = 1\\) s and \\(t = 2\\) s.' },
      { q: 'A particle moves so that \\(s = 5t - t^2\\) metres. Find the position of the particle when \\(t = 4\\).', marks: 2, tier: 'green', modelAnswer: 'Substitute \\(t = 4\\): \\(s = 5(4) - (4)^2 = 20 - 16 = 4\\) m.' },
      { q: 'A particle has displacement \\(s = t^3 - 3t^2 + 2\\) metres. Find the position when \\(t = 3\\).', marks: 2, tier: 'green', modelAnswer: 'Substitute \\(t = 3\\): \\(s = 27 - 27 + 2 = 2\\) m.' },
      { q: 'A particle moves with velocity \\(v = 3t^2 - 12\\) m/s. Find when the particle is at rest.', marks: 2, tier: 'green', modelAnswer: 'Set \\(v = 0\\): \\(3t^2 = 12\\), so \\(t^2 = 4\\), giving \\(t = 2\\) s (taking positive value).' },
      { q: 'A particle has displacement \\(s = 4t^2 - t^3\\) metres at time \\(t \\geq 0\\). Find the velocity and acceleration at \\(t = 1\\).', marks: 3, tier: 'green', modelAnswer: 'Differentiate: \\(v = 8t - 3t^2\\). At \\(t = 1\\): \\(v = 8 - 3 = 5\\) m/s. Differentiate again: \\(a = 8 - 6t\\). At \\(t = 1\\): \\(a = 8 - 6 = 2\\) m/s².' },
      { q: 'A particle has velocity \\(v = (2t-1)(t+3)\\) m/s. Find the times when the particle is at rest.', marks: 3, tier: 'green', modelAnswer: 'Expand: \\(v = 2t^2 + 6t - t - 3 = 2t^2 + 5t - 3\\). Set \\(v = 0\\): \\((2t - 1)(t + 3) = 0\\), so \\(t = \\frac{1}{2}\\) s or \\(t = -3\\) s. Since \\(t \\geq 0\\), the particle is at rest at \\(t = 0.5\\) s.' },
      { q: 'A particle moves so that \\(s = t^4 - 8t^2 + 3\\) metres. Find \\(v\\) and \\(a\\) as functions of \\(t\\).', marks: 2, tier: 'green', modelAnswer: '\\(v = \\dfrac{ds}{dt} = 4t^3 - 16t\\) m/s. \\(a = \\dfrac{dv}{dt} = 12t^2 - 16\\) m/s².' },
      { q: 'A particle moves with displacement \\(s = 6\\sqrt{t} = 6t^{1/2}\\) metres, \\(t > 0\\). Find the velocity at \\(t = 4\\).', marks: 3, tier: 'green', modelAnswer: 'Differentiate: \\(v = 6 \\times \\frac{1}{2} t^{-1/2} = \\dfrac{3}{\\sqrt{t}}\\). At \\(t = 4\\): \\(v = \\dfrac{3}{2} = 1.5\\) m/s.' },
      { q: 'A particle has velocity \\(v = 10 - 2t\\) m/s. Find the acceleration and determine whether the particle is decelerating.', marks: 2, tier: 'green', modelAnswer: '\\(a = \\dfrac{dv}{dt} = -2\\) m/s². Since the acceleration is negative and constant, the particle is decelerating throughout its motion.' },
      { q: 'A particle has displacement \\(s = t^3 - 6t^2 + 9t + 2\\) metres. Find the position of the particle when it is first at rest.', marks: 4, tier: 'green', modelAnswer: 'Differentiate: \\(v = 3t^2 - 12t + 9 = 3(t^2 - 4t + 3) = 3(t-1)(t-3)\\). First at rest at \\(t = 1\\). Position: \\(s = 1 - 6 + 9 + 2 = 6\\) m.' },
    ],
    amber: [
      { q: 'A particle starts from rest at the origin. Its acceleration is \\(a = 6t - 4\\) m/s². Find the velocity as a function of \\(t\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(v = \\int (6t - 4)\\, dt = 3t^2 - 4t + C\\). At \\(t = 0\\), \\(v = 0\\), so \\(C = 0\\). Therefore \\(v = 3t^2 - 4t\\) m/s.' },
      { q: 'A particle has acceleration \\(a = 12t^2 - 6t\\) m/s². When \\(t = 0\\), \\(v = 5\\) m/s. Find \\(v\\) as a function of \\(t\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(v = \\int (12t^2 - 6t)\\, dt = 4t^3 - 3t^2 + C\\). At \\(t = 0\\), \\(v = 5\\), so \\(C = 5\\). Therefore \\(v = 4t^3 - 3t^2 + 5\\) m/s.' },
      { q: 'A particle moves with velocity \\(v = 3t^2 - 6t\\) m/s. When \\(t = 0\\), the particle is at the origin. Find the displacement at \\(t = 4\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(s = \\int (3t^2 - 6t)\\, dt = t^3 - 3t^2 + C\\). At \\(t = 0\\), \\(s = 0\\), so \\(C = 0\\). At \\(t = 4\\): \\(s = 64 - 48 = 16\\) m.' },
      { q: 'A particle has velocity \\(v = t^2 - 4t + 3\\) m/s and displacement \\(s = 2\\) m when \\(t = 0\\). Find the displacement when \\(t = 5\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(s = \\dfrac{t^3}{3} - 2t^2 + 3t + C\\). At \\(t = 0\\), \\(s = 2\\), so \\(C = 2\\). At \\(t = 5\\): \\(s = \\dfrac{125}{3} - 50 + 15 + 2 = \\dfrac{125}{3} - 33 = \\dfrac{125 - 99}{3} = \\dfrac{26}{3}\\) m.' },
      { q: 'A particle moves with velocity \\(v = t^2 - 5t + 4\\) m/s for \\(t \\geq 0\\). Find the total distance travelled between \\(t = 0\\) and \\(t = 4\\).', marks: 6, tier: 'amber', modelAnswer: 'Find when \\(v = 0\\): \\((t-1)(t-4) = 0\\), so \\(t = 1\\) or \\(t = 4\\). \\(s = \\int_0^1 (t^2 - 5t + 4)\\, dt = \\left[\\dfrac{t^3}{3} - \\dfrac{5t^2}{2} + 4t\\right]_0^1 = \\dfrac{1}{3} - \\dfrac{5}{2} + 4 = \\dfrac{11}{6}\\). \\(s = \\int_1^4 (t^2 - 5t + 4)\\, dt = \\left[\\dfrac{t^3}{3} - \\dfrac{5t^2}{2} + 4t\\right]_1^4 = (\\dfrac{64}{3} - 40 + 16) - (\\dfrac{1}{3} - \\dfrac{5}{2} + 4) = -\\dfrac{9}{2}\\). Total distance = \\(\\dfrac{11}{6} + \\dfrac{9}{2} = \\dfrac{11}{6} + \\dfrac{27}{6} = \\dfrac{38}{6} = \\dfrac{19}{3}\\) m.' },
      { q: 'A particle starts from the origin with velocity \\(v = 6t - t^2\\) m/s. Find when the particle returns to the origin.', marks: 5, tier: 'amber', modelAnswer: 'Integrate: \\(s = 3t^2 - \\dfrac{t^3}{3} + C\\). At \\(t = 0\\), \\(s = 0\\), so \\(C = 0\\). Set \\(s = 0\\): \\(t^2(3 - \\dfrac{t}{3}) = 0\\), so \\(t = 0\\) or \\(t = 9\\) s. The particle returns to the origin at \\(t = 9\\) s.' },
      { q: 'A particle has acceleration \\(a = 4 - 2t\\) m/s². When \\(t = 0\\), \\(v = 3\\) m/s and \\(s = 0\\). Find the maximum displacement of the particle.', marks: 5, tier: 'amber', modelAnswer: 'Integrate: \\(v = 4t - t^2 + 3\\). Maximum displacement when \\(v = 0\\): \\(-t^2 + 4t + 3 = 0\\), so \\(t^2 - 4t - 3 = 0\\), \\(t = \\dfrac{4 \\pm \\sqrt{16+12}}{2} = \\dfrac{4 \\pm \\sqrt{28}}{2} = 2 \\pm \\sqrt{7}\\). Taking positive root: \\(t = 2 + \\sqrt{7}\\). Integrate again: \\(s = 2t^2 - \\dfrac{t^3}{3} + 3t\\). At \\(t = 2+\\sqrt{7}\\): compute \\(s_{\\max}\\). Numerically \\(t \\approx 4.646\\): \\(s \\approx 2(21.59) - \\frac{100.1}{3} + 13.94 \\approx 43.18 - 33.37 + 13.94 \\approx 23.8\\) m.' },
      { q: 'A particle moves with velocity \\(v = 2t^3 - 9t^2 + 12t\\) m/s, starting from the origin. Find the displacement when \\(t = 3\\) and the total distance travelled in the interval \\(0 \\leq t \\leq 3\\).', marks: 6, tier: 'amber', modelAnswer: 'Integrate for \\(s\\): \\(s = \\dfrac{t^4}{2} - 3t^3 + 6t^2\\). At \\(t = 3\\): \\(s = \\frac{81}{2} - 81 + 54 = 40.5 - 81 + 54 = 13.5\\) m. Find where \\(v = 0\\): \\(t(2t^2 - 9t + 12) = 0\\). Discriminant of quadratic: \\(81 - 96 < 0\\), so \\(v = 0\\) only at \\(t = 0\\). Since \\(v \\geq 0\\) for \\(t \\in [0,3]\\) (check \\(v(1) = 2-9+12 = 5 > 0\\)), total distance = displacement = 13.5 m.' },
      { q: 'A particle has acceleration \\(a = (3t-1)^2\\) m/s². When \\(t = 1\\), \\(v = 4\\) m/s. Find \\(v\\) when \\(t = 2\\).', marks: 4, tier: 'amber', modelAnswer: 'Expand: \\(a = 9t^2 - 6t + 1\\). Integrate: \\(v = 3t^3 - 3t^2 + t + C\\). At \\(t = 1\\): \\(4 = 3 - 3 + 1 + C\\), so \\(C = 3\\). At \\(t = 2\\): \\(v = 3(8) - 3(4) + 2 + 3 = 24 - 12 + 2 + 3 = 17\\) m/s.' },
      { q: 'A particle moves from rest at the origin with acceleration \\(a = e^{2t}\\) m/s². Find the velocity and displacement at \\(t = 1\\). (Use exact values.)', marks: 5, tier: 'amber', modelAnswer: 'Integrate: \\(v = \\dfrac{e^{2t}}{2} + C\\). At \\(t = 0\\), \\(v = 0\\): \\(0 = \\frac{1}{2} + C\\), so \\(C = -\\frac{1}{2}\\). Thus \\(v = \\dfrac{e^{2t} - 1}{2}\\). At \\(t = 1\\): \\(v = \\dfrac{e^2 - 1}{2}\\) m/s. Integrate: \\(s = \\dfrac{e^{2t}}{4} - \\dfrac{t}{2} + D\\). At \\(t = 0\\), \\(s = 0\\): \\(D = -\\frac{1}{4}\\). At \\(t = 1\\): \\(s = \\dfrac{e^2}{4} - \\dfrac{1}{2} - \\dfrac{1}{4} = \\dfrac{e^2 - 3}{4}\\) m.' },
      { q: 'A particle has velocity \\(v = \\sin(2t)\\) m/s. Find the displacement from \\(t = 0\\) to \\(t = \\dfrac{\\pi}{2}\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(s = \\int_0^{\\pi/2} \\sin(2t)\\, dt = \\left[-\\dfrac{\\cos(2t)}{2}\\right]_0^{\\pi/2} = -\\dfrac{\\cos \\pi}{2} + \\dfrac{\\cos 0}{2} = \\dfrac{1}{2} + \\dfrac{1}{2} = 1\\) m.' },
      { q: 'A particle moves with velocity \\(v = t^2 - 6t + 8\\) m/s. Find the total distance travelled between \\(t = 0\\) and \\(t = 5\\).', marks: 6, tier: 'amber', modelAnswer: 'Find roots: \\((t-2)(t-4) = 0\\), so \\(t = 2, 4\\). \\(\\int_0^2 (t^2-6t+8)\\,dt = \\left[\\frac{t^3}{3}-3t^2+8t\\right]_0^2 = \\frac{8}{3}-12+16 = \\frac{8}{3}+4 = \\frac{20}{3}\\). \\(\\int_2^4 (t^2-6t+8)\\,dt = \\left[\\frac{t^3}{3}-3t^2+8t\\right]_2^4 = (\\frac{64}{3}-48+32)-(\\frac{8}{3}-12+16) = -\\frac{4}{3}-\\frac{20}{3} = -8\\). \\(\\int_4^5 (t^2-6t+8)\\,dt = \\left[\\frac{t^3}{3}-3t^2+8t\\right]_4^5 = (\\frac{125}{3}-75+40)-(\\frac{64}{3}-48+32) = \\frac{61}{3}-35-\\frac{16}{3}+16 = \\frac{45}{3}-19 = 15-19 = -4\\). Wait — recompute \\(\\int_4^5\\): \\((\\frac{125}{3}-75+40) = \\frac{125}{3}-35\\); \\((\\frac{64}{3}-48+32) = \\frac{64}{3}-16\\). Difference: \\(\\frac{61}{3}-19 = \\frac{61-57}{3} = \\frac{4}{3}\\). Total distance = \\(\\frac{20}{3} + 8 + \\frac{4}{3} = \\frac{24}{3}+8 = 8+8 = 16\\) m.' },
      { q: 'A particle starts from rest at a point O. It accelerates with \\(a = 3t^2 - 2t\\) m/s² for \\(t \\geq 0\\). Find the distance from O when \\(t = 3\\).', marks: 4, tier: 'amber', modelAnswer: 'Integrate: \\(v = t^3 - t^2 + C\\). At \\(t = 0\\), \\(v = 0\\) so \\(C = 0\\). Integrate: \\(s = \\dfrac{t^4}{4} - \\dfrac{t^3}{3} + D\\). At \\(t = 0\\), \\(s = 0\\) so \\(D = 0\\). At \\(t = 3\\): \\(s = \\dfrac{81}{4} - \\dfrac{27}{3} = \\dfrac{81}{4} - 9 = \\dfrac{81 - 36}{4} = \\dfrac{45}{4} = 11.25\\) m.' },
      { q: 'A particle has displacement \\(s = t^3 - 6t^2 + 9t\\) m. Find the maximum displacement for \\(t \\geq 0\\) before the particle reverses.', marks: 4, tier: 'amber', modelAnswer: 'Differentiate: \\(v = 3t^2 - 12t + 9 = 3(t-1)(t-3)\\). First stationary point at \\(t = 1\\). \\(s(1) = 1 - 6 + 9 = 4\\) m. At \\(t = 3\\): \\(s(3) = 27 - 54 + 27 = 0\\). So the maximum displacement is 4 m, reached at \\(t = 1\\) s.' },
      { q: 'A particle has acceleration \\(a = \\dfrac{4}{t^2}\\) m/s² for \\(t > 0\\). When \\(t = 2\\), \\(v = 3\\) m/s. Find \\(v\\) when \\(t = 4\\).', marks: 4, tier: 'amber', modelAnswer: 'Write \\(a = 4t^{-2}\\). Integrate: \\(v = -4t^{-1} + C = -\\dfrac{4}{t} + C\\). At \\(t = 2\\), \\(v = 3\\): \\(3 = -2 + C\\), so \\(C = 5\\). At \\(t = 4\\): \\(v = -1 + 5 = 4\\) m/s.' },
    ],
    red: [
      { q: 'A particle moves along the x-axis. Its velocity satisfies \\(v\\dfrac{dv}{ds} = 4s - 2\\). When \\(s = 0\\), \\(v = 2\\) m/s. Find \\(v^2\\) as a function of \\(s\\), and find \\(v\\) when \\(s = 3\\).', marks: 6, tier: 'red', modelAnswer: 'Use \\(a = v\\dfrac{dv}{ds}\\). So \\(v\\,dv = (4s-2)\\,ds\\). Integrate both sides: \\(\\dfrac{v^2}{2} = 2s^2 - 2s + C\\). At \\(s = 0\\), \\(v = 2\\): \\(\\dfrac{4}{2} = 0 + C\\), so \\(C = 2\\). Therefore \\(v^2 = 4s^2 - 4s + 4\\). At \\(s = 3\\): \\(v^2 = 36 - 12 + 4 = 28\\), so \\(v = \\sqrt{28} = 2\\sqrt{7}\\) m/s.' },
      { q: 'A particle moves so that \\(a = v \\dfrac{dv}{ds} = 3v^2\\). When \\(s = 0\\), \\(v = 1\\) m/s. Find \\(v\\) as a function of \\(s\\).', marks: 6, tier: 'red', modelAnswer: 'Separate variables: \\(\\dfrac{dv}{ds} = 3v\\). So \\(\\dfrac{1}{v}\\,dv = 3\\,ds\\). Integrate: \\(\\ln|v| = 3s + C\\). At \\(s = 0\\), \\(v = 1\\): \\(\\ln 1 = 0 + C\\), so \\(C = 0\\). Therefore \\(\\ln v = 3s\\), giving \\(v = e^{3s}\\) m/s.' },
      { q: 'A particle P moves in 2D so that its position vector is \\(\\mathbf{r} = (t^2 - 3t)\\mathbf{i} + (2t^3 - t)\\mathbf{j}\\) metres, \\(t \\geq 0\\). Find the speed of P when \\(t = 2\\).', marks: 6, tier: 'red', modelAnswer: 'Differentiate: \\(\\mathbf{v} = \\dfrac{d\\mathbf{r}}{dt} = (2t-3)\\mathbf{i} + (6t^2-1)\\mathbf{j}\\). At \\(t = 2\\): \\(\\mathbf{v} = (4-3)\\mathbf{i} + (24-1)\\mathbf{j} = \\mathbf{i} + 23\\mathbf{j}\\). Speed \\(= \\sqrt{1^2 + 23^2} = \\sqrt{1 + 529} = \\sqrt{530}\\) m/s.' },
      { q: 'A particle has position vector \\(\\mathbf{r} = (t^3 - 4t)\\mathbf{i} + (t^2 - 3t + 2)\\mathbf{j}\\) metres. Find when the velocity is parallel to \\(\\mathbf{i}\\) (i.e. the \\(\\mathbf{j}\\)-component of velocity is zero).', marks: 5, tier: 'red', modelAnswer: 'Differentiate: \\(\\mathbf{v} = (3t^2 - 4)\\mathbf{i} + (2t - 3)\\mathbf{j}\\). For velocity parallel to \\(\\mathbf{i}\\), the \\(\\mathbf{j}\\)-component must be zero: \\(2t - 3 = 0\\), so \\(t = \\dfrac{3}{2}\\) s.' },
      { q: 'A particle has position vector \\(\\mathbf{r} = (2t^2 - t)\\mathbf{i} + (t^3 - 3t)\\mathbf{j}\\) metres. Find when the velocity is parallel to the vector \\(\\mathbf{i} + \\mathbf{j}\\).', marks: 6, tier: 'red', modelAnswer: 'Differentiate: \\(\\mathbf{v} = (4t-1)\\mathbf{i} + (3t^2-3)\\mathbf{j}\\). For velocity parallel to \\(\\mathbf{i} + \\mathbf{j}\\), the components must be equal: \\(4t - 1 = 3t^2 - 3\\). Rearrange: \\(3t^2 - 4t - 2 = 0\\). Using the quadratic formula: \\(t = \\dfrac{4 \\pm \\sqrt{16 + 24}}{6} = \\dfrac{4 \\pm \\sqrt{40}}{6} = \\dfrac{4 \\pm 2\\sqrt{10}}{6} = \\dfrac{2 \\pm \\sqrt{10}}{3}\\). Taking positive root (\\(t \\geq 0\\)): \\(t = \\dfrac{2 + \\sqrt{10}}{3}\\) s.' },
      { q: 'A particle moves along a line so that \\(v = 4\\sqrt{s}\\) m/s. Use \\(a = v\\dfrac{dv}{ds}\\) to find the acceleration when \\(s = 9\\) m.', marks: 6, tier: 'red', modelAnswer: '\\(v = 4s^{1/2}\\). Differentiate with respect to \\(s\\): \\(\\dfrac{dv}{ds} = 2s^{-1/2}\\). Then \\(a = v\\dfrac{dv}{ds} = 4s^{1/2} \\times 2s^{-1/2} = 8\\) m/s². So the acceleration is constant at 8 m/s² (independent of \\(s\\)). At \\(s = 9\\): \\(a = 8\\) m/s².' },
      { q: 'A particle P has position vector \\(\\mathbf{r} = (3\\cos t)\\mathbf{i} + (3\\sin t)\\mathbf{j}\\) metres. Show that the speed is constant and find it. Find the acceleration vector and its magnitude.', marks: 7, tier: 'red', modelAnswer: '\\(\\mathbf{v} = (-3\\sin t)\\mathbf{i} + (3\\cos t)\\mathbf{j}\\). Speed \\(= \\sqrt{9\\sin^2 t + 9\\cos^2 t} = \\sqrt{9} = 3\\) m/s (constant). \\(\\mathbf{a} = (-3\\cos t)\\mathbf{i} + (-3\\sin t)\\mathbf{j} = -\\mathbf{r}\\). Magnitude of acceleration \\(= \\sqrt{9\\cos^2 t + 9\\sin^2 t} = 3\\) m/s².' },
      { q: 'A particle has position vector \\(\\mathbf{r} = (t^2 + 1)\\mathbf{i} + (2t - t^2)\\mathbf{j}\\). Find when the particle is moving perpendicular to \\(\\mathbf{i} + \\mathbf{j}\\).', marks: 7, tier: 'red', modelAnswer: '\\(\\mathbf{v} = 2t\\mathbf{i} + (2 - 2t)\\mathbf{j}\\). For perpendicular to \\(\\mathbf{i} + \\mathbf{j}\\), the dot product must be zero: \\(\\mathbf{v} \\cdot (\\mathbf{i} + \\mathbf{j}) = 2t + (2 - 2t) = 2 \\neq 0\\). So the velocity is never perpendicular to \\(\\mathbf{i} + \\mathbf{j}\\). (The sum of components is always 2.) Note: this demonstrates the importance of checking — a well-posed version might use \\(\\mathbf{i} - \\mathbf{j}\\): \\(2t - (2-2t) = 4t - 2 = 0\\) gives \\(t = \\frac{1}{2}\\) s.' },
      { q: 'A particle moves so that its acceleration is \\(a = v\\dfrac{dv}{ds} = 2s + 3\\). When \\(s = 1\\), \\(v = 3\\) m/s. Find \\(v\\) when \\(s = 4\\).', marks: 6, tier: 'red', modelAnswer: '\\(v\\,dv = (2s+3)\\,ds\\). Integrate: \\(\\dfrac{v^2}{2} = s^2 + 3s + C\\). At \\(s = 1\\), \\(v = 3\\): \\(\\dfrac{9}{2} = 1 + 3 + C\\), so \\(C = \\dfrac{9}{2} - 4 = \\dfrac{1}{2}\\). Therefore \\(v^2 = 2s^2 + 6s + 1\\). At \\(s = 4\\): \\(v^2 = 32 + 24 + 1 = 57\\), so \\(v = \\sqrt{57}\\) m/s.' },
      { q: 'A particle P moves in 2D with velocity \\(\\mathbf{v} = (2t - 4)\\mathbf{i} + (t^2 - 2t)\\mathbf{j}\\) m/s. At \\(t = 0\\), P is at position \\(3\\mathbf{i} + \\mathbf{j}\\). Find the position of P when its velocity is parallel to \\(\\mathbf{i}\\).', marks: 8, tier: 'red', modelAnswer: 'Velocity parallel to \\(\\mathbf{i}\\) means \\(\\mathbf{j}\\)-component is zero: \\(t^2 - 2t = 0\\), so \\(t(t-2) = 0\\), giving \\(t = 0\\) or \\(t = 2\\). At \\(t = 0\\), \\(v_i = -4\\) (moving in \\(-\\mathbf{i}\\) direction). Check \\(t = 2\\). Integrate \\(\\mathbf{v}\\) for position: \\(\\mathbf{r} = (t^2 - 4t + C_1)\\mathbf{i} + (\\dfrac{t^3}{3} - t^2 + C_2)\\mathbf{j}\\). At \\(t = 0\\): \\(C_1 = 3, C_2 = 1\\). So \\(\\mathbf{r} = (t^2-4t+3)\\mathbf{i} + (\\dfrac{t^3}{3}-t^2+1)\\mathbf{j}\\). At \\(t = 2\\): \\(\\mathbf{r} = (4-8+3)\\mathbf{i} + (\\dfrac{8}{3}-4+1)\\mathbf{j} = -\\mathbf{i} + (\\dfrac{8}{3}-3)\\mathbf{j} = -\\mathbf{i} - \\dfrac{1}{3}\\mathbf{j}\\). Position is \\(-\\mathbf{i} - \\dfrac{1}{3}\\mathbf{j}\\) m.' },
    ],
  },

  'M6': {
    name: 'Projectiles',
    green: [
      { q: 'A ball is thrown horizontally from the top of a cliff 45 m high with speed 20 m/s. Find the time of flight. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Vertical motion from rest: \\(s = \\frac{1}{2}g t^2\\). \\(45 = \\frac{1}{2}(9.8)t^2\\). \\(t^2 = \\dfrac{90}{9.8} = \\dfrac{450}{49}\\). \\(t = \\dfrac{\\sqrt{450}}{7} = \\dfrac{15\\sqrt{2}}{7} \\approx 3.03\\) s.', diagram: true },
      { q: 'A stone is thrown horizontally at 15 m/s from a height of 20 m. Find the horizontal range. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'green', modelAnswer: 'First find time: \\(20 = \\frac{1}{2}(9.8)t^2\\), so \\(t^2 = \\dfrac{40}{9.8}\\), \\(t = \\sqrt{\\dfrac{40}{9.8}} \\approx 2.020\\) s. Horizontal range: \\(R = 15t = 15 \\times 2.020 \\approx 30.3\\) m.', diagram: true },
      { q: 'A particle is projected horizontally at 25 m/s from a height of 80 m. Find the speed at impact. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'green', modelAnswer: 'Find time of flight: \\(80 = \\frac{1}{2}(9.8)t^2\\), \\(t^2 = \\dfrac{160}{9.8}\\), \\(t \\approx 4.040\\) s. Vertical speed at impact: \\(v_y = 9.8 \\times 4.040 \\approx 39.6\\) m/s. Speed \\(= \\sqrt{25^2 + 39.6^2} = \\sqrt{625 + 1568.2} \\approx \\sqrt{2193} \\approx 46.8\\) m/s.' },
      { q: 'A ball is projected at \\(30°\\) to the horizontal with speed 20 m/s. Find the maximum height reached. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Vertical component: \\(u_y = 20\\sin 30° = 10\\) m/s. At max height, \\(v_y = 0\\). Use \\(v^2 = u^2 - 2gs\\): \\(0 = 100 - 2(9.8)H\\), so \\(H = \\dfrac{100}{19.6} \\approx 5.10\\) m.' },
      { q: 'A particle is projected at angle \\(60°\\) above the horizontal with speed 14 m/s. Find the maximum height. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(u_y = 14\\sin 60° = 14 \\times \\frac{\\sqrt{3}}{2} = 7\\sqrt{3}\\) m/s. At max height: \\(0 = (7\\sqrt{3})^2 - 2(9.8)H\\), so \\(H = \\dfrac{147}{19.6} = 7.5\\) m.' },
      { q: 'A particle is projected horizontally with speed \\(U\\) m/s from height \\(h\\) m. Write down expressions for the horizontal and vertical components of velocity after time \\(t\\).', marks: 2, tier: 'green', modelAnswer: 'Horizontal (no acceleration): \\(v_x = U\\) m/s (constant). Vertical (starting from rest, downwards positive): \\(v_y = gt\\) m/s.' },
      { q: 'A cricket ball is projected at \\(45°\\) with speed 28 m/s. Find the time to reach maximum height. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: '\\(u_y = 28\\sin 45° = 28 \\times \\frac{\\sqrt{2}}{2} = 14\\sqrt{2}\\) m/s. At max height, \\(v_y = 0\\): \\(0 = 14\\sqrt{2} - 9.8t\\), so \\(t = \\dfrac{14\\sqrt{2}}{9.8} = \\dfrac{10\\sqrt{2}}{7} \\approx 2.02\\) s.' },
      { q: 'A ball is projected at \\(30°\\) to the horizontal with speed 40 m/s. Find the horizontal component and vertical component of the initial velocity.', marks: 2, tier: 'green', modelAnswer: 'Horizontal: \\(u_x = 40\\cos 30° = 40 \\times \\frac{\\sqrt{3}}{2} = 20\\sqrt{3} \\approx 34.6\\) m/s. Vertical: \\(u_y = 40\\sin 30° = 40 \\times \\frac{1}{2} = 20\\) m/s.' },
      { q: 'A particle is projected horizontally from a height of 5 m. Find the time it takes to hit the ground. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: 'Vertical: \\(5 = \\frac{1}{2}(9.8)t^2\\), so \\(t^2 = \\dfrac{10}{9.8} = \\dfrac{50}{49}\\), \\(t = \\dfrac{5\\sqrt{2}}{7} \\approx 1.01\\) s.' },
      { q: 'A projectile is launched at \\(\\theta = 45°\\) with speed 19.6 m/s. Find the time of flight. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(u_y = 19.6 \\sin 45° = 19.6 \\times \\frac{\\sqrt{2}}{2} = 9.8\\sqrt{2}\\) m/s. Time to max height: \\(t_1 = \\dfrac{9.8\\sqrt{2}}{9.8} = \\sqrt{2}\\) s. By symmetry, total time of flight \\(= 2\\sqrt{2} \\approx 2.83\\) s.' },
      { q: 'A particle is projected at \\(\\alpha°\\) above the horizontal. The initial speed is \\(U\\). Write an expression for the horizontal range \\(R\\) on a flat surface. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Time of flight: \\(T = \\dfrac{2U\\sin\\alpha}{g}\\). Range: \\(R = U\\cos\\alpha \\times T = \\dfrac{U^2 \\times 2\\sin\\alpha\\cos\\alpha}{g} = \\dfrac{U^2\\sin 2\\alpha}{g}\\).' },
      { q: 'A ball is projected at \\(60°\\) with initial speed 10 m/s. Find the horizontal range when it lands at the same level. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(R = \\dfrac{U^2 \\sin 2\\alpha}{g} = \\dfrac{100 \\times \\sin 120°}{9.8} = \\dfrac{100 \\times \\frac{\\sqrt{3}}{2}}{9.8} = \\dfrac{50\\sqrt{3}}{9.8} \\approx 8.84\\) m.' },
      { q: 'A particle is launched horizontally at 12 m/s from the top of a building. Find the vertical speed after 2 seconds. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: 'Vertical velocity starts at 0. After 2 s: \\(v_y = g \\times t = 9.8 \\times 2 = 19.6\\) m/s (downwards).' },
      { q: 'A particle is projected with speed 30 m/s at angle \\(\\alpha\\) to the horizontal, where \\(\\sin\\alpha = 0.6\\). Find the vertical component of initial velocity.', marks: 2, tier: 'green', modelAnswer: '\\(u_y = 30\\sin\\alpha = 30 \\times 0.6 = 18\\) m/s.' },
      { q: 'A ball is projected at \\(30°\\) with speed 20 m/s from ground level. Find the time of flight and show it is about 2.04 s. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(u_y = 20\\sin 30° = 10\\) m/s. Time of flight: \\(T = \\dfrac{2 \\times 10}{9.8} = \\dfrac{20}{9.8} \\approx 2.04\\) s, as required.' },
    ],
    amber: [
      { q: 'A particle is projected from ground level at speed 30 m/s at angle \\(40°\\) to the horizontal. Find (a) the maximum height, (b) the range. (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'amber', modelAnswer: '\\(u_x = 30\\cos 40° \\approx 22.98\\) m/s; \\(u_y = 30\\sin 40° \\approx 19.28\\) m/s. (a) Max height: \\(H = \\dfrac{u_y^2}{2g} = \\dfrac{19.28^2}{19.6} \\approx \\dfrac{371.7}{19.6} \\approx 18.97\\) m. (b) Time of flight: \\(T = \\dfrac{2u_y}{g} = \\dfrac{2 \\times 19.28}{9.8} \\approx 3.935\\) s. Range: \\(R = u_x T \\approx 22.98 \\times 3.935 \\approx 90.4\\) m.', diagram: true },
      { q: 'A ball is projected from a point on a cliff 60 m above the sea at an angle of \\(30°\\) above the horizontal with speed 20 m/s. Find the time of flight until it hits the sea. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Taking upward as positive, downward displacement = 60 m. \\(u_y = 20\\sin 30° = 10\\) m/s. Vertical: \\(-60 = 10t - \\frac{1}{2}(9.8)t^2\\). Rearrange: \\(4.9t^2 - 10t - 60 = 0\\). Discriminant: \\(100 + 4(4.9)(60) = 100 + 1176 = 1276\\). \\(t = \\dfrac{10 + \\sqrt{1276}}{9.8} = \\dfrac{10 + 35.72}{9.8} \\approx \\dfrac{45.72}{9.8} \\approx 4.67\\) s.', diagram: true },
      { q: 'A particle is projected at angle \\(25°\\) below the horizontal from the top of a tower 50 m high, with speed 15 m/s. Find when it reaches the ground. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Taking downward positive: \\(u_y = 15\\sin 25° \\approx 6.34\\) m/s. Vertical: \\(50 = 6.34t + 4.9t^2\\). Rearrange: \\(4.9t^2 + 6.34t - 50 = 0\\). Discriminant: \\(40.2 + 4(4.9)(50) = 40.2 + 980 = 1020.2\\). \\(t = \\dfrac{-6.34 + \\sqrt{1020.2}}{9.8} \\approx \\dfrac{-6.34 + 31.94}{9.8} \\approx \\dfrac{25.6}{9.8} \\approx 2.61\\) s.', diagram: true },
      { q: 'A particle is projected with speed 25 m/s at \\(35°\\) to the horizontal. Find the time(s) when the particle is at a height of 10 m. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(u_y = 25\\sin 35° \\approx 14.34\\) m/s. Vertical: \\(10 = 14.34t - 4.9t^2\\). Rearrange: \\(4.9t^2 - 14.34t + 10 = 0\\). Discriminant: \\(14.34^2 - 4(4.9)(10) = 205.6 - 196 = 9.6\\). \\(t = \\dfrac{14.34 \\pm \\sqrt{9.6}}{9.8} = \\dfrac{14.34 \\pm 3.098}{9.8}\\). So \\(t \\approx 1.78\\) s or \\(t \\approx 1.15\\) s.' },
      { q: 'A ball is projected from O with speed 18 m/s at \\(50°\\) to the horizontal. Find the speed and direction of motion of the ball after 2 seconds. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(u_x = 18\\cos 50° \\approx 11.57\\) m/s; \\(u_y = 18\\sin 50° \\approx 13.79\\) m/s. After 2 s: \\(v_x = 11.57\\) m/s; \\(v_y = 13.79 - 9.8(2) = 13.79 - 19.6 = -5.81\\) m/s (downward). Speed \\(= \\sqrt{11.57^2 + 5.81^2} = \\sqrt{133.9 + 33.8} = \\sqrt{167.7} \\approx 12.95\\) m/s. Angle below horizontal: \\(\\theta = \\arctan\\left(\\dfrac{5.81}{11.57}\\right) \\approx 26.7°\\).' },
      { q: 'A particle is projected from ground level and reaches a maximum height of 20 m. Find the vertical component of its initial velocity. Hence find the time of flight. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: 'At max height \\(v_y = 0\\): \\(0 = u_y^2 - 2(9.8)(20)\\), so \\(u_y^2 = 392\\), \\(u_y = \\sqrt{392} = 14\\sqrt{2} \\approx 19.80\\) m/s. Time of flight: \\(T = \\dfrac{2u_y}{g} = \\dfrac{2 \\times 14\\sqrt{2}}{9.8} = \\dfrac{28\\sqrt{2}}{9.8} = \\dfrac{20\\sqrt{2}}{7} \\approx 4.04\\) s.' },
      { q: 'A particle is projected at \\(\\alpha°\\) above the horizontal from the edge of a cliff 80 m high, with \\(\\cos\\alpha = 0.6\\) and speed 25 m/s. Find the horizontal distance from the base of the cliff when it hits the ground. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(\\cos\\alpha = 0.6\\), so \\(\\sin\\alpha = 0.8\\). \\(u_x = 25 \\times 0.6 = 15\\) m/s; \\(u_y = 25 \\times 0.8 = 20\\) m/s. Vertical (taking down as negative, so \\(s = -80\\)): \\(-80 = 20t - 4.9t^2\\). So \\(4.9t^2 - 20t - 80 = 0\\). Discriminant: \\(400 + 4(4.9)(80) = 400 + 1568 = 1968\\). \\(t = \\dfrac{20 + \\sqrt{1968}}{9.8} \\approx \\dfrac{20 + 44.36}{9.8} \\approx 6.567\\) s. Horizontal distance: \\(15 \\times 6.567 \\approx 98.5\\) m.', diagram: true },
      { q: 'A particle is projected horizontally from the top of a cliff at 10 m/s. It hits the sea at a point which is 50 m horizontally from the base of the cliff. Find the height of the cliff. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: 'Time of flight: \\(t = \\dfrac{50}{10} = 5\\) s. Height: \\(h = \\dfrac{1}{2}(9.8)(5)^2 = 4.9 \\times 25 = 122.5\\) m.' },
      { q: 'A ball is hit from ground level at \\(45°\\) to the horizontal. It just clears a wall of height 8 m at a horizontal distance of 20 m. Find the initial speed of the ball. (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'amber', modelAnswer: '\\(u_x = U\\cos 45° = \\frac{U}{\\sqrt{2}}\\); \\(u_y = U\\sin 45° = \\frac{U}{\\sqrt{2}}\\). Time to reach wall: \\(t = \\dfrac{20}{U/\\sqrt{2}} = \\dfrac{20\\sqrt{2}}{U}\\). Vertical height at wall: \\(8 = \\frac{U}{\\sqrt{2}} \\cdot \\frac{20\\sqrt{2}}{U} - \\frac{1}{2}(9.8)\\left(\\frac{20\\sqrt{2}}{U}\\right)^2 = 20 - \\frac{4.9 \\times 800}{U^2}\\). So \\(\\frac{3920}{U^2} = 12\\), \\(U^2 = \\frac{3920}{12} = \\frac{980}{3}\\), \\(U = \\sqrt{\\frac{980}{3}} \\approx 18.07\\) m/s.' },
      { q: 'Two particles are projected simultaneously from the same point with the same speed but at angles \\(30°\\) and \\(60°\\) to the horizontal. Show that they have the same range.', marks: 4, tier: 'amber', modelAnswer: 'Range formula: \\(R = \\dfrac{U^2 \\sin 2\\alpha}{g}\\). For \\(\\alpha = 30°\\): \\(\\sin 60° = \\frac{\\sqrt{3}}{2}\\). For \\(\\alpha = 60°\\): \\(\\sin 120° = \\sin(180°-60°) = \\sin 60° = \\frac{\\sqrt{3}}{2}\\). Since \\(\\sin 2(30°) = \\sin 2(60°)\\), the ranges are equal: \\(R = \\dfrac{U^2 \\sqrt{3}}{2g}\\). QED.' },
      { q: 'A particle is projected with speed 20 m/s at \\(\\theta°\\) above horizontal from a point 15 m above the ground. Find the range if \\(\\theta = 30°\\). (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(u_x = 20\\cos 30° = 10\\sqrt{3}\\) m/s; \\(u_y = 20\\sin 30° = 10\\) m/s. Vertical (down = negative): \\(-15 = 10t - 4.9t^2\\). Rearrange: \\(4.9t^2 - 10t - 15 = 0\\). Discriminant: \\(100 + 294 = 394\\). \\(t = \\dfrac{10 + \\sqrt{394}}{9.8} \\approx \\dfrac{10 + 19.85}{9.8} \\approx 3.045\\) s. Range: \\(10\\sqrt{3} \\times 3.045 \\approx 17.32 \\times 3.045 \\approx 52.7\\) m.' },
      { q: 'A stone is thrown from the top of a wall of height 12 m at 45° above horizontal with speed 14 m/s. Find the total time of flight and where it lands. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(u_x = u_y = 14\\cos 45° = 7\\sqrt{2} \\approx 9.899\\) m/s. Vertical (down = negative): \\(-12 = 7\\sqrt{2} \\cdot t - 4.9t^2\\). \\(4.9t^2 - 7\\sqrt{2}t - 12 = 0\\). Discriminant: \\((7\\sqrt{2})^2 + 4(4.9)(12) = 98 + 235.2 = 333.2\\). \\(t = \\dfrac{7\\sqrt{2} + \\sqrt{333.2}}{9.8} \\approx \\dfrac{9.899 + 18.254}{9.8} \\approx 2.872\\) s. Range: \\(9.899 \\times 2.872 \\approx 28.4\\) m from base of wall.' },
      { q: 'A ball is launched at speed 15 m/s and hits the ground at the same level after 2.5 s. Find the angle of projection and the range. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: 'Time of flight: \\(T = \\dfrac{2u\\sin\\theta}{g}\\). So \\(2.5 = \\dfrac{2(15)\\sin\\theta}{9.8}\\), giving \\(\\sin\\theta = \\dfrac{2.5 \\times 9.8}{30} = \\dfrac{24.5}{30} = \\dfrac{49}{60}\\), \\(\\theta = \\arcsin\\left(\\dfrac{49}{60}\\right) \\approx 54.8°\\). Range: \\(R = 15\\cos\\theta \\times 2.5\\). \\(\\cos\\theta = \\sqrt{1 - (\\frac{49}{60})^2} = \\sqrt{\\frac{3600-2401}{3600}} = \\sqrt{\\frac{1199}{3600}} \\approx 0.5773\\). \\(R = 15 \\times 0.5773 \\times 2.5 \\approx 21.6\\) m.' },
      { q: 'A particle is projected at angle \\(\\alpha\\) with initial speed \\(U\\). Show that the time of flight on a horizontal plane is \\(T = \\dfrac{2U\\sin\\alpha}{g}\\) and the maximum height is \\(H = \\dfrac{U^2\\sin^2\\alpha}{2g}\\).', marks: 4, tier: 'amber', modelAnswer: 'Vertical motion: \\(s = U\\sin\\alpha \\cdot t - \\frac{1}{2}g t^2\\). At landing \\(s = 0\\): \\(t(U\\sin\\alpha - \\frac{g}{2}t) = 0\\). Non-zero solution: \\(T = \\dfrac{2U\\sin\\alpha}{g}\\). At max height, \\(v_y = 0\\): \\(v_y^2 = U^2\\sin^2\\alpha - 2gH = 0\\), so \\(H = \\dfrac{U^2\\sin^2\\alpha}{2g}\\). QED.' },
      { q: 'A particle is projected at \\(\\theta = 55°\\) with speed 22 m/s from a point on a cliff 30 m high. Find the horizontal distance travelled when the particle is at the same height as the launch point (on the way down). (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: '\\(u_y = 22\\sin 55° \\approx 18.02\\) m/s; \\(u_x = 22\\cos 55° \\approx 12.62\\) m/s. Time to return to same height: \\(T = \\dfrac{2 \\times 18.02}{9.8} \\approx 3.678\\) s. Horizontal distance: \\(12.62 \\times 3.678 \\approx 46.4\\) m.' },
    ],
    red: [
      { q: 'Show that the range of a projectile on a horizontal plane is maximised when \\(\\theta = 45°\\). (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'red', modelAnswer: 'Range: \\(R = \\dfrac{U^2 \\sin 2\\theta}{g}\\). To maximise \\(R\\), we maximise \\(\\sin 2\\theta\\). The maximum value of \\(\\sin 2\\theta\\) is 1, which occurs when \\(2\\theta = 90°\\), i.e. \\(\\theta = 45°\\). Maximum range: \\(R_{\\max} = \\dfrac{U^2}{g}\\). QED.' },
      { q: 'Particle A is projected from O at \\(30°\\) above horizontal with speed 20 m/s. Particle B is projected simultaneously from a point 40 m away horizontally (at the same height) directly towards A at \\(150°\\) to the positive x-axis (i.e. \\(30°\\) above horizontal, moving left) with speed 20 m/s. Determine whether A and B collide. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Both particles have the same vertical motion (same \\(u_y = 10\\) m/s, same \\(g\\)), so they are always at the same height at the same time. Set A at origin. A\'s horizontal position: \\(x_A = 20\\cos 30° \\cdot t = 10\\sqrt{3}\\, t\\). B starts at \\(x = 40\\) and moves left: \\(x_B = 40 - 20\\cos 30° \\cdot t = 40 - 10\\sqrt{3}\\, t\\). Set \\(x_A = x_B\\): \\(10\\sqrt{3}\\, t = 40 - 10\\sqrt{3}\\, t\\), so \\(20\\sqrt{3}\\, t = 40\\), \\(t = \\dfrac{2}{\\sqrt{3}} = \\dfrac{2\\sqrt{3}}{3} \\approx 1.155\\) s. Since they are at the same height (by symmetry of vertical motion) and same horizontal position at \\(t \\approx 1.155\\) s, they collide.', diagram: true },
      { q: 'A particle is projected with initial speed \\(U\\) at angle \\(\\alpha\\) to the horizontal. It passes through the point \\((60, 20)\\) where distances are in metres (horizontal and vertical). Given \\(\\alpha = 45°\\) and \\(g = 9.8\\) m/s², find \\(U\\).', marks: 7, tier: 'red', modelAnswer: '\\(u_x = \\frac{U}{\\sqrt{2}}\\); \\(u_y = \\frac{U}{\\sqrt{2}}\\). Time to reach \\(x = 60\\): \\(t = \\dfrac{60}{U/\\sqrt{2}} = \\dfrac{60\\sqrt{2}}{U}\\). Vertical: \\(20 = \\frac{U}{\\sqrt{2}} \\cdot \\frac{60\\sqrt{2}}{U} - \\frac{1}{2}(9.8)\\left(\\frac{60\\sqrt{2}}{U}\\right)^2 = 60 - \\frac{4.9 \\times 7200}{U^2}\\). So \\(\\frac{35280}{U^2} = 40\\), \\(U^2 = \\frac{35280}{40} = 882\\), \\(U = \\sqrt{882} = 21\\sqrt{2} \\approx 29.7\\) m/s.' },
      { q: 'A particle is projected at speed \\(U\\) m/s at angle \\(\\alpha\\) to the horizontal. By eliminating \\(t\\), show that the Cartesian equation of the path is \\(y = x\\tan\\alpha - \\dfrac{gx^2}{2U^2\\cos^2\\alpha}\\).', marks: 6, tier: 'red', modelAnswer: 'Horizontal: \\(x = U\\cos\\alpha \\cdot t\\), so \\(t = \\dfrac{x}{U\\cos\\alpha}\\). Substitute into vertical: \\(y = U\\sin\\alpha \\cdot t - \\dfrac{1}{2}g t^2 = U\\sin\\alpha \\cdot \\dfrac{x}{U\\cos\\alpha} - \\dfrac{g}{2}\\left(\\dfrac{x}{U\\cos\\alpha}\\right)^2 = x\\tan\\alpha - \\dfrac{gx^2}{2U^2\\cos^2\\alpha}\\). QED.' },
      { q: 'Using the Cartesian equation \\(y = x\\tan\\alpha - \\dfrac{gx^2}{2U^2\\cos^2\\alpha}\\), find the range on a horizontal surface by setting \\(y = 0\\).', marks: 5, tier: 'red', modelAnswer: 'Set \\(y = 0\\): \\(x\\tan\\alpha - \\dfrac{gx^2}{2U^2\\cos^2\\alpha} = 0\\). Factor out \\(x\\): \\(x\\left(\\tan\\alpha - \\dfrac{gx}{2U^2\\cos^2\\alpha}\\right) = 0\\). Non-zero solution: \\(x = \\dfrac{2U^2\\cos^2\\alpha \\tan\\alpha}{g} = \\dfrac{2U^2\\cos^2\\alpha \\cdot \\sin\\alpha}{g\\cos\\alpha} = \\dfrac{2U^2\\sin\\alpha\\cos\\alpha}{g} = \\dfrac{U^2\\sin 2\\alpha}{g}\\). This is the range formula.' },
      { q: 'Particle A is projected from the top of a cliff 100 m high with speed 30 m/s at \\(20°\\) above the horizontal. Particle B is projected from the bottom of the cliff horizontally with speed 15 m/s at the same instant. Do the particles meet? If so, when and where? (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Take origin at base of cliff. A: \\(x_A = 30\\cos 20° \\cdot t \\approx 28.19t\\); \\(y_A = 100 + 30\\sin 20° \\cdot t - 4.9t^2 \\approx 100 + 10.26t - 4.9t^2\\). B: \\(x_B = 15t\\); \\(y_B = 0 + 0 - 4.9t^2\\). Wait — B is projected from the bottom, so \\(y_B\\) starts at 0 and since it is horizontal, \\(y_B = -4.9t^2\\) (below ground) which is impossible. B must land when \\(y_B = 0\\), immediately. Re-read: B moves horizontally from base at height 0, so \\(y_B = 0\\) throughout — but then it is on the ground. The particles cannot meet since A is at height \\(\\approx 100 + 10.26t - 4.9t^2 > 0\\) initially, and B is on the ground. They do not meet.' },
      { q: 'A particle is projected from the origin with speed \\(U\\) at \\(45°\\). Find the coordinates of the highest point and the point where it lands. Verify that the horizontal distance of the highest point from the origin is half the range. (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'red', modelAnswer: '\\(u_x = u_y = \\frac{U}{\\sqrt{2}}\\). Time to max height: \\(t_1 = \\dfrac{u_y}{g} = \\dfrac{U}{g\\sqrt{2}}\\). Max height coords: \\(x_1 = u_x t_1 = \\frac{U}{\\sqrt{2}} \\cdot \\frac{U}{g\\sqrt{2}} = \\dfrac{U^2}{2g}\\); \\(y_1 = \\dfrac{u_y^2}{2g} = \\dfrac{U^2}{4g}\\). Range: \\(R = \\dfrac{U^2\\sin 90°}{g} = \\dfrac{U^2}{g}\\). Half range \\(= \\dfrac{U^2}{2g} = x_1\\). Verified.' },
      { q: 'A projectile is observed to pass through two points A\\((10, 6)\\) and B\\((20, 8)\\) where coordinates are in metres. Find the initial speed and angle of projection. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Use \\(y = x\\tan\\alpha - \\dfrac{gx^2}{2U^2\\cos^2\\alpha}\\). Let \\(k = \\dfrac{g}{2U^2\\cos^2\\alpha}\\). At A: \\(6 = 10\\tan\\alpha - 100k\\). At B: \\(8 = 20\\tan\\alpha - 400k\\). From A: \\(100k = 10\\tan\\alpha - 6\\). From B: \\(400k = 20\\tan\\alpha - 8\\). Divide: \\(4(10\\tan\\alpha - 6) = 20\\tan\\alpha - 8\\), so \\(40\\tan\\alpha - 24 = 20\\tan\\alpha - 8\\), \\(20\\tan\\alpha = 16\\), \\(\\tan\\alpha = 0.8\\), \\(\\alpha = \\arctan(0.8) \\approx 38.7°\\). Then \\(k = \\dfrac{10(0.8)-6}{100} = \\dfrac{2}{100} = 0.02\\). \\(\\cos^2\\alpha = \\dfrac{1}{1+\\tan^2\\alpha} = \\dfrac{1}{1.64} \\approx 0.6098\\). \\(U^2 = \\dfrac{g}{2k\\cos^2\\alpha} = \\dfrac{9.8}{2(0.02)(0.6098)} = \\dfrac{9.8}{0.02439} \\approx 401.8\\). \\(U \\approx 20.0\\) m/s.', diagram: true },
      { q: 'A particle is projected from a point O on horizontal ground. It just clears a wall of height 4 m, 10 m away from O, and lands 5 m beyond the wall. Find the initial speed and angle of projection. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'The particle passes through \\((10, 4)\\) and lands at \\((15, 0)\\). From landing: \\(0 = 15\\tan\\alpha - \\dfrac{g(15)^2}{2U^2\\cos^2\\alpha}\\), so \\(\\dfrac{225g}{2U^2\\cos^2\\alpha} = 15\\tan\\alpha\\), giving \\(\\dfrac{g}{2U^2\\cos^2\\alpha} = \\dfrac{\\tan\\alpha}{15}\\). At wall: \\(4 = 10\\tan\\alpha - \\dfrac{100g}{2U^2\\cos^2\\alpha} = 10\\tan\\alpha - \\dfrac{100\\tan\\alpha}{15} = 10\\tan\\alpha - \\dfrac{20\\tan\\alpha}{3} = \\tan\\alpha\\left(10 - \\frac{20}{3}\\right) = \\dfrac{10\\tan\\alpha}{3}\\). So \\(\\tan\\alpha = \\dfrac{12}{10} = 1.2\\), \\(\\alpha = \\arctan(1.2) \\approx 50.2°\\). \\(k = \\dfrac{\\tan\\alpha}{15} = \\dfrac{1.2}{15} = 0.08\\). \\(\\cos^2\\alpha = \\dfrac{1}{1+1.44} = \\dfrac{1}{2.44}\\). \\(U^2 = \\dfrac{g}{2 \\times 0.08 \\times \\cos^2\\alpha} = \\dfrac{9.8 \\times 2.44}{0.16} \\approx \\dfrac{23.91}{0.16} \\approx 149.5\\). \\(U \\approx 12.2\\) m/s.', diagram: true },
      { q: 'A ball is kicked from O on level ground at speed 15 m/s and angle \\(\\alpha\\). It passes over a post of height \\(h\\) m at horizontal distance 18 m. Given the ball just clears the post (\\(h\\) is maximum possible), find \\(\\alpha\\) and \\(h\\). (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Height at \\(x = 18\\): \\(y = 18\\tan\\alpha - \\dfrac{9.8(18)^2}{2(15)^2\\cos^2\\alpha} = 18\\tan\\alpha - \\dfrac{9.8 \\times 324}{450\\cos^2\\alpha} = 18\\tan\\alpha - \\dfrac{3175.2}{450}\\sec^2\\alpha\\). Use \\(\\sec^2\\alpha = 1 + \\tan^2\\alpha\\): \\(y = 18\\tan\\alpha - 7.056(1 + \\tan^2\\alpha)\\). Let \\(T = \\tan\\alpha\\): \\(y = 18T - 7.056 - 7.056T^2\\). Maximise over \\(T\\): \\(\\dfrac{dy}{dT} = 18 - 14.112T = 0\\), so \\(T = \\dfrac{18}{14.112} = \\dfrac{75}{58.8} \\approx 1.2755\\), \\(\\alpha \\approx 51.9°\\). Max \\(y = 18(1.2755) - 7.056 - 7.056(1.2755)^2 \\approx 22.96 - 7.056 - 11.481 \\approx 4.42\\) m. So \\(h \\approx 4.42\\) m.', diagram: true },
    ],
  },

  'M7': {
    name: 'Further Forces (Friction)',
    green: [
      { q: 'A block of mass 5 kg rests on a rough horizontal surface. The coefficient of friction is \\(\\mu = 0.3\\). Find the maximum friction force. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: 'Normal reaction: \\(R = mg = 5 \\times 9.8 = 49\\) N. Maximum friction: \\(F = \\mu R = 0.3 \\times 49 = 14.7\\) N.' },
      { q: 'A particle of mass 8 kg is on a rough horizontal surface (\\(\\mu = 0.4\\)). A horizontal force of 20 N is applied. Find the friction force and state whether the particle moves. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Normal reaction: \\(R = 8 \\times 9.8 = 78.4\\) N. Max friction: \\(F_{\\max} = 0.4 \\times 78.4 = 31.36\\) N. Since \\(20 < 31.36\\), the particle does not move. Friction force = 20 N (opposing applied force, at equilibrium).' },
      { q: 'State the law of friction and explain the condition for limiting equilibrium.', marks: 2, tier: 'green', modelAnswer: 'The law of friction states: \\(F \\leq \\mu R\\), where \\(F\\) is the friction force, \\(R\\) is the normal reaction, and \\(\\mu\\) is the coefficient of friction. At limiting equilibrium, the friction force is at its maximum: \\(F = \\mu R\\), i.e. the particle is on the verge of slipping.' },
      { q: 'A box of mass 10 kg is pushed along a rough floor (\\(\\mu = 0.25\\)) by a horizontal force. Find the force required to maintain constant speed. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Normal reaction: \\(R = 10 \\times 9.8 = 98\\) N. For constant speed, driving force = friction force = \\(\\mu R = 0.25 \\times 98 = 24.5\\) N.' },
      { q: 'A particle of mass 6 kg moves on a rough horizontal surface (\\(\\mu = 0.5\\)). A horizontal force of 50 N acts. Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Normal reaction: \\(R = 6 \\times 9.8 = 58.8\\) N. Friction: \\(F = \\mu R = 0.5 \\times 58.8 = 29.4\\) N. Net force: \\(50 - 29.4 = 20.6\\) N. Acceleration: \\(a = \\dfrac{20.6}{6} \\approx 3.43\\) m/s².' },
      { q: 'A particle of mass 4 kg rests on a rough horizontal surface. A horizontal force P is applied. If \\(\\mu = 0.6\\) and the particle is in limiting equilibrium, find P. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: '\\(R = 4 \\times 9.8 = 39.2\\) N. At limiting equilibrium: \\(P = F = \\mu R = 0.6 \\times 39.2 = 23.52\\) N.' },
      { q: 'Define the coefficient of friction \\(\\mu\\) and give its typical range of values.', marks: 2, tier: 'green', modelAnswer: 'The coefficient of friction \\(\\mu = \\dfrac{F}{R}\\) at the point of sliding, where \\(F\\) is the friction force and \\(R\\) is the normal reaction. It is dimensionless and typically \\(0 < \\mu < 1\\) for most surfaces (though it can exceed 1 for very rough surfaces).' },
      { q: 'A block of mass 3 kg on a rough horizontal surface (\\(\\mu = 0.4\\)) is pushed by a force of 15 N at an angle of \\(0°\\) (horizontal). Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Normal reaction: \\(R = 3 \\times 9.8 = 29.4\\) N. Friction: \\(F = 0.4 \\times 29.4 = 11.76\\) N. Net force: \\(15 - 11.76 = 3.24\\) N. Acceleration: \\(a = \\dfrac{3.24}{3} = 1.08\\) m/s².' },
      { q: 'A particle of mass 2 kg is placed on a rough horizontal surface. A horizontal force of 10 N just causes the particle to move. Find \\(\\mu\\). (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: 'At limiting equilibrium: \\(F = P = 10\\) N; \\(R = 2 \\times 9.8 = 19.6\\) N. \\(\\mu = \\dfrac{F}{R} = \\dfrac{10}{19.6} \\approx 0.510\\).' },
      { q: 'A particle is on a rough horizontal floor. Friction acts on the particle. In what direction does friction act if the particle is moving to the right?', marks: 2, tier: 'green', modelAnswer: 'Friction always acts to oppose the direction of motion (or impending motion). If the particle moves to the right, friction acts to the left.' },
      { q: 'A block of mass 12 kg rests on rough ground (\\(\\mu = 0.35\\)). Find (a) the normal reaction and (b) the maximum friction force. (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: '(a) \\(R = 12 \\times 9.8 = 117.6\\) N. (b) \\(F_{\\max} = \\mu R = 0.35 \\times 117.6 = 41.16\\) N.' },
      { q: 'A particle of mass 5 kg is pulled along a rough horizontal surface (\\(\\mu = 0.2\\)) by a horizontal force. It accelerates at 1.5 m/s². Find the applied force. (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(R = 5 \\times 9.8 = 49\\) N. Friction: \\(F = 0.2 \\times 49 = 9.8\\) N. Newton\'s second law: \\(P - 9.8 = 5 \\times 1.5 = 7.5\\). So \\(P = 9.8 + 7.5 = 17.3\\) N.' },
      { q: 'A book of mass 1.5 kg is on a rough desk. A horizontal force of 6 N is just sufficient to maintain it at rest (the force is applied to resist it sliding). If the only other horizontal force is friction, find \\(\\mu\\). (\\(g = 9.8\\) m/s²)', marks: 2, tier: 'green', modelAnswer: '\\(R = 1.5 \\times 9.8 = 14.7\\) N. At limiting equilibrium, friction = 6 N. \\(\\mu = \\dfrac{6}{14.7} \\approx 0.408\\).' },
      { q: 'A particle of mass 7 kg is on a rough horizontal surface. A force of 30 N is applied horizontally. The particle accelerates at 2 m/s². Find \\(\\mu\\). (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: '\\(R = 7 \\times 9.8 = 68.6\\) N. Net force = \\(7 \\times 2 = 14\\) N. Friction: \\(F = 30 - 14 = 16\\) N. \\(\\mu = \\dfrac{16}{68.6} \\approx 0.233\\).' },
      { q: 'A crate of mass 20 kg sits on a rough floor. A person pushes horizontally with force 100 N but the crate does not move. Find the friction force and state whether the friction is at its limit if \\(\\mu = 0.6\\). (\\(g = 9.8\\) m/s²)', marks: 3, tier: 'green', modelAnswer: 'Since the crate is in equilibrium, friction = applied force = 100 N. Max friction: \\(F_{\\max} = \\mu R = 0.6 \\times 20 \\times 9.8 = 117.6\\) N. Since \\(100 < 117.6\\), friction is not at its limit.' },
    ],
    amber: [
      { q: 'A particle of mass 5 kg slides down a rough inclined plane (angle \\(30°\\), \\(\\mu = 0.2\\)). Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Normal reaction: \\(R = mg\\cos 30° = 5 \\times 9.8 \\times \\frac{\\sqrt{3}}{2} = 49 \\times \\frac{\\sqrt{3}}{2} \\approx 42.44\\) N. Friction (opposing motion, so acting up slope): \\(F = \\mu R = 0.2 \\times 42.44 = 8.49\\) N. Driving force down slope: \\(mg\\sin 30° = 49 \\times 0.5 = 24.5\\) N. Net force down slope: \\(24.5 - 8.49 = 16.01\\) N. Acceleration: \\(a = \\dfrac{16.01}{5} \\approx 3.20\\) m/s².', diagram: true },
      { q: 'A block of mass 8 kg is pushed up a rough inclined plane (angle \\(25°\\), \\(\\mu = 0.3\\)) by a force P parallel to the slope. Find P for the block to move at constant speed. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Normal reaction: \\(R = mg\\cos 25° = 8 \\times 9.8 \\times \\cos 25° \\approx 78.4 \\times 0.9063 \\approx 71.05\\) N. Friction (opposing motion up slope, so acting down slope): \\(F = \\mu R = 0.3 \\times 71.05 \\approx 21.32\\) N. For constant speed (no acceleration), \\(P = mg\\sin 25° + F = 78.4 \\times \\sin 25° + 21.32 \\approx 78.4 \\times 0.4226 + 21.32 \\approx 33.13 + 21.32 \\approx 54.45\\) N.', diagram: true },
      { q: 'A particle of mass 4 kg is on a rough slope (angle \\(\\alpha\\)) and slides down with acceleration 1.2 m/s². Find \\(\\mu\\) given \\(\\sin\\alpha = 0.5\\). (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(\\cos\\alpha = \\sqrt{1 - 0.25} = \\frac{\\sqrt{3}}{2}\\). \\(R = mg\\cos\\alpha = 4 \\times 9.8 \\times \\frac{\\sqrt{3}}{2} = 19.6\\sqrt{3} \\approx 33.95\\) N. Friction up slope: \\(F = \\mu R\\). Net force down slope = \\(ma\\): \\(mg\\sin\\alpha - F = 4 \\times 1.2\\). \\(4 \\times 9.8 \\times 0.5 - \\mu \\times 33.95 = 4.8\\). \\(19.6 - 4.8 = \\mu \\times 33.95\\). \\(\\mu = \\dfrac{14.8}{33.95} \\approx 0.436\\).' },
      { q: 'A particle of mass 6 kg rests on a rough plane inclined at angle \\(\\theta\\). The particle is about to slip. If \\(\\mu = 0.45\\), find \\(\\theta\\).', marks: 4, tier: 'amber', modelAnswer: 'At limiting equilibrium on an incline: \\(\\tan\\theta = \\mu\\). So \\(\\tan\\theta = 0.45\\), giving \\(\\theta = \\arctan(0.45) \\approx 24.2°\\). (Mass is not needed as it cancels.)' },
      { q: 'A particle of mass 3 kg is on a rough incline (\\(\\mu = 0.5\\), angle \\(\\theta\\) where \\(\\tan\\theta = 0.75\\)). A force of \\(P\\) N acts up the slope. The particle is in equilibrium. Find the range of values of \\(P\\). (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'amber', modelAnswer: '\\(\\tan\\theta = 0.75 = \\frac{3}{4}\\), so \\(\\sin\\theta = 0.6\\), \\(\\cos\\theta = 0.8\\). \\(R = 3 \\times 9.8 \\times 0.8 = 23.52\\) N. \\(mg\\sin\\theta = 3 \\times 9.8 \\times 0.6 = 17.64\\) N. Max friction \\(= 0.5 \\times 23.52 = 11.76\\) N. For particle not to slip down: \\(P + F_{\\text{up}} \\geq mg\\sin\\theta\\), i.e. \\(P \\geq 17.64 - 11.76 = 5.88\\) N. For particle not to slip up: \\(P \\leq mg\\sin\\theta + F_{\\text{down}} = 17.64 + 11.76 = 29.4\\) N. So \\(5.88 \\leq P \\leq 29.4\\) N.' },
      { q: 'A particle of mass 10 kg is on a rough plane (\\(\\mu = 0.4\\)) inclined at \\(20°\\) to the horizontal. A horizontal force of \\(Q\\) N is applied. The particle is about to slide up the plane. Find \\(Q\\). (\\(g = 9.8\\) m/s²)', marks: 6, tier: 'amber', modelAnswer: 'Resolving perpendicular to slope: \\(R = mg\\cos 20° + Q\\sin 20°\\). Resolving parallel to slope (about to slide up, so friction acts down): \\(Q\\cos 20° = mg\\sin 20° + \\mu R\\). Substitute \\(R\\): \\(Q\\cos 20° = mg\\sin 20° + \\mu(mg\\cos 20° + Q\\sin 20°)\\). \\(Q(\\cos 20° - \\mu\\sin 20°) = mg(\\sin 20° + \\mu\\cos 20°)\\). With \\(m = 10\\), \\(g = 9.8\\), \\(\\mu = 0.4\\), \\(\\cos 20° \\approx 0.9397\\), \\(\\sin 20° \\approx 0.3420\\): \\(Q(0.9397 - 0.4 \\times 0.3420) = 98(0.3420 + 0.4 \\times 0.9397)\\). \\(Q(0.9397 - 0.1368) = 98(0.3420 + 0.3759)\\). \\(Q(0.8029) = 98(0.7179) = 70.35\\). \\(Q = \\dfrac{70.35}{0.8029} \\approx 87.6\\) N.', diagram: true },
      { q: 'A particle rests on a rough inclined plane of angle \\(35°\\). It is on the verge of sliding down. Find \\(\\mu\\).', marks: 3, tier: 'amber', modelAnswer: 'At limiting equilibrium about to slide down: \\(mg\\sin 35° = \\mu mg\\cos 35°\\), so \\(\\mu = \\tan 35° \\approx 0.700\\).' },
      { q: 'A sledge of mass 15 kg rests on a rough slope (\\(\\mu = 0.3\\), angle \\(\\theta\\) where \\(\\sin\\theta = 0.4\\)). A rope parallel to the slope pulls the sledge up. Find the tension in the rope when the sledge moves at constant speed. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: '\\(\\cos\\theta = \\sqrt{1 - 0.16} = \\sqrt{0.84} \\approx 0.9165\\). \\(R = 15 \\times 9.8 \\times 0.9165 \\approx 134.72\\) N. Friction (down slope, opposing upward motion): \\(F = 0.3 \\times 134.72 \\approx 40.42\\) N. \\(mg\\sin\\theta = 15 \\times 9.8 \\times 0.4 = 58.8\\) N. Tension: \\(T = mg\\sin\\theta + F = 58.8 + 40.42 = 99.22\\) N.' },
      { q: 'A particle of mass 5 kg is on a rough inclined plane (angle \\(\\theta\\), \\(\\mu = 0.6\\)). It is pushed UP the slope by a force of 80 N parallel to the slope, and accelerates at \\(a\\) m/s². Find \\(a\\) given \\(\\sin\\theta = 0.6\\), \\(\\cos\\theta = 0.8\\). (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: '\\(R = mg\\cos\\theta = 5 \\times 9.8 \\times 0.8 = 39.2\\) N. Friction (opposes motion up slope, acts down slope): \\(F = 0.6 \\times 39.2 = 23.52\\) N. \\(mg\\sin\\theta = 5 \\times 9.8 \\times 0.6 = 29.4\\) N. Net force up slope: \\(80 - 29.4 - 23.52 = 27.08\\) N. \\(a = \\dfrac{27.08}{5} \\approx 5.42\\) m/s².' },
      { q: 'A particle of mass 2 kg is on a rough slope (\\(\\mu = 0.3\\), angle \\(40°\\)). A force is applied down the slope. Find the acceleration if the force is 5 N. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: '\\(R = 2 \\times 9.8 \\times \\cos 40° \\approx 19.6 \\times 0.7660 \\approx 15.01\\) N. \\(mg\\sin 40° \\approx 19.6 \\times 0.6428 \\approx 12.60\\) N. The particle is pushed down, so check friction direction. Gravity component + applied force both act down, so particle accelerates down and friction acts up. Friction: \\(F = 0.3 \\times 15.01 \\approx 4.50\\) N. Net force down: \\(12.60 + 5 - 4.50 = 13.10\\) N. \\(a = \\dfrac{13.10}{2} = 6.55\\) m/s².' },
      { q: 'A particle of mass 4 kg is on a rough horizontal surface (\\(\\mu = 0.5\\)). It is pulled by a string at angle \\(20°\\) above horizontal with tension \\(T\\). Find the minimum value of \\(T\\) to move the particle. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Perpendicular: \\(R + T\\sin 20° = mg\\), so \\(R = mg - T\\sin 20° = 39.2 - T\\sin 20°\\). Horizontal (at limiting equilibrium): \\(T\\cos 20° = \\mu R = 0.5(39.2 - T\\sin 20°)\\). \\(T\\cos 20° + 0.5T\\sin 20° = 19.6\\). \\(T(\\cos 20° + 0.5\\sin 20°) = 19.6\\). \\(T(0.9397 + 0.5 \\times 0.3420) = 19.6\\). \\(T(0.9397 + 0.1710) = T(1.1107) = 19.6\\). \\(T = \\dfrac{19.6}{1.1107} \\approx 17.65\\) N.' },
      { q: 'A particle rests on a rough inclined plane. If the angle is increased from \\(20°\\) to \\(30°\\), and \\(\\mu = 0.5\\), determine whether the particle slips.', marks: 4, tier: 'amber', modelAnswer: 'The particle slips when \\(\\tan\\theta > \\mu\\). At \\(20°\\): \\(\\tan 20° \\approx 0.364 < 0.5\\) — no slip. At \\(30°\\): \\(\\tan 30° \\approx 0.577 > 0.5\\) — the particle slips. So increasing the angle to \\(30°\\) causes the particle to slip.' },
      { q: 'A particle of mass 9 kg rests in equilibrium on a rough plane (angle \\(\\alpha\\), \\(\\mu = 0.4\\)) under gravity alone. Find the maximum value of \\(\\alpha\\).', marks: 3, tier: 'amber', modelAnswer: 'Maximum angle before slipping: \\(\\tan\\alpha = \\mu = 0.4\\). \\(\\alpha_{\\max} = \\arctan(0.4) \\approx 21.8°\\).' },
      { q: 'A box of mass 12 kg is on a rough floor (\\(\\mu = 0.35\\)). A force of 45 N acts at \\(30°\\) below the horizontal (pushing down and forward). Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 5, tier: 'amber', modelAnswer: 'Vertical: \\(R = mg + F\\sin 30° = 12 \\times 9.8 + 45 \\times 0.5 = 117.6 + 22.5 = 140.1\\) N. Friction: \\(\\mu R = 0.35 \\times 140.1 = 49.04\\) N. Horizontal: net force \\(= F\\cos 30° - \\text{friction} = 45 \\times 0.8660 - 49.04 = 38.97 - 49.04 = -10.07\\) N. Since the net force is negative, the applied force is not sufficient to move the box (friction exceeds the horizontal component of F). The box remains stationary; the applied horizontal force = 38.97 N, friction = 38.97 N.' },
      { q: 'A particle of mass 6 kg slides down a rough slope (\\(\\mu = 0.2\\)) inclined at \\(\\theta\\) where \\(\\cos\\theta = 0.9\\), \\(\\sin\\theta = \\sqrt{1-0.81} \\approx 0.436\\). Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 4, tier: 'amber', modelAnswer: '\\(R = 6 \\times 9.8 \\times 0.9 = 52.92\\) N. Friction (up slope): \\(F = 0.2 \\times 52.92 = 10.58\\) N. Down slope force: \\(mg\\sin\\theta = 6 \\times 9.8 \\times 0.436 \\approx 25.64\\) N. Net force: \\(25.64 - 10.58 = 15.06\\) N. \\(a = \\dfrac{15.06}{6} \\approx 2.51\\) m/s².' },
    ],
    red: [
      { q: 'Particle A (mass 3 kg) rests on a rough inclined plane (angle \\(30°\\), \\(\\mu = 0.3\\)) connected by a light string over a smooth pulley at the top to particle B (mass 2 kg) hanging freely. Find the acceleration of the system and the tension in the string. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Check if system moves: Force pulling A up = weight of B = \\(2 \\times 9.8 = 19.6\\) N. Force pulling A down slope = \\(3 \\times 9.8 \\times \\sin 30° = 14.7\\) N. Normal reaction on A: \\(R = 3 \\times 9.8 \\times \\cos 30° = 29.4 \\times \\frac{\\sqrt{3}}{2} \\approx 25.46\\) N. Max friction = \\(0.3 \\times 25.46 \\approx 7.64\\) N. Net force without friction: \\(19.6 - 14.7 = 4.9\\) N (pulling A up). Since \\(4.9 < 7.64\\), friction can keep the system in equilibrium — but we need to check whether B causes motion up the slope. Net upward force along slope from B: \\(19.6 - 14.7 = 4.9\\) N < max friction \\(7.64\\) N. So system is in equilibrium. \\(a = 0\\), friction = 4.9 N (down slope on A). If the problem intends motion: For motion with B going down and A going up slope: \\((2 + 3)a = 19.6 - 14.7 - 7.64 = -2.74\\) N < 0, confirming no motion.', diagram: true },
      { q: 'Particle A (mass 5 kg) is on a rough inclined plane (angle \\(\\theta\\), \\(\\sin\\theta = 0.6\\), \\(\\cos\\theta = 0.8\\), \\(\\mu = 0.25\\)) connected by a string over a pulley to particle B (mass 4 kg) hanging freely. Find the acceleration and tension. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Check direction: B\'s weight = \\(4 \\times 9.8 = 39.2\\) N. A\'s component down slope = \\(5 \\times 9.8 \\times 0.6 = 29.4\\) N. B\'s weight > A\'s down-slope component, so A is pulled UP the slope (and B descends). Friction on A acts DOWN the slope. \\(R = 5 \\times 9.8 \\times 0.8 = 39.2\\) N. Friction = \\(0.25 \\times 39.2 = 9.8\\) N. For A (up slope positive): \\(T - 29.4 - 9.8 = 5a\\), so \\(T - 39.2 = 5a\\). For B (downward positive): \\(39.2 - T = 4a\\). Add: \\(0 = 9a - 0\\)... \\(39.2 - 39.2 = 9a\\), so \\(a = 0\\). System is in equilibrium. Tension: from B equation: \\(T = 39.2 - 4(0) = 39.2\\) N. Friction check: required friction = \\(T - 29.4 = 9.8\\) N = max friction. System is in limiting equilibrium.', diagram: true },
      { q: 'A particle of mass 4 kg rests on a rough slope (angle \\(40°\\), \\(\\mu = 0.4\\)) under the action of a force P up the slope. Find the range of values of P for which the particle remains in equilibrium. (\\(g = 9.8\\) m/s²)', marks: 7, tier: 'red', modelAnswer: '\\(mg\\sin 40° = 4 \\times 9.8 \\times \\sin 40° \\approx 39.2 \\times 0.6428 \\approx 25.20\\) N. \\(R = mg\\cos 40° \\approx 39.2 \\times 0.7660 \\approx 30.03\\) N. Max friction \\(= 0.4 \\times 30.03 \\approx 12.01\\) N. For particle not to slide DOWN (P + friction up \\(\\geq mg\\sin\\theta\\)): \\(P \\geq mg\\sin\\theta - F_{\\max} = 25.20 - 12.01 = 13.19\\) N. For particle not to slide UP (P \\(\\leq mg\\sin\\theta + F_{\\max}\\)): \\(P \\leq 25.20 + 12.01 = 37.21\\) N. Range: \\(13.19 \\leq P \\leq 37.21\\) N (approximately).', diagram: true },
      { q: 'A particle of mass 6 kg is on a rough inclined plane (angle \\(30°\\), \\(\\mu = 0.5\\)). A force P acts horizontally on the particle. Find the value of P that causes the particle to be on the verge of moving UP the slope. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Perpendicular to slope: \\(R = mg\\cos 30° + P\\sin 30°\\). \\(R = 6 \\times 9.8 \\times \\frac{\\sqrt{3}}{2} + P \\times \\frac{1}{2} = 50.92 + 0.5P\\). Parallel to slope (about to move up, so friction acts down slope): \\(P\\cos 30° = mg\\sin 30° + \\mu R\\). \\(P \\times \\frac{\\sqrt{3}}{2} = 6 \\times 9.8 \\times \\frac{1}{2} + 0.5(50.92 + 0.5P)\\). \\(0.8660P = 29.4 + 25.46 + 0.25P\\). \\(0.8660P - 0.25P = 54.86\\). \\(0.6160P = 54.86\\). \\(P = \\dfrac{54.86}{0.6160} \\approx 89.1\\) N.', diagram: true },
      { q: 'A particle of mass 5 kg is on a rough slope (angle \\(\\theta\\), \\(\\tan\\theta = \\frac{3}{4}\\), \\(\\mu = 0.5\\)). A force P acts horizontally. Show that the particle will slip up if \\(P > P_1\\) and slip down if \\(P < P_2\\), and find \\(P_1\\) and \\(P_2\\). (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: '\\(\\sin\\theta = 0.6\\), \\(\\cos\\theta = 0.8\\). \\(mg = 49\\) N. \\(mg\\sin\\theta = 29.4\\) N; \\(mg\\cos\\theta = 39.2\\) N. \\(R = mg\\cos\\theta + P\\sin\\theta = 39.2 + 0.6P\\). Max friction \\(= 0.5R = 19.6 + 0.3P\\). Parallel to slope: \\(P\\cos\\theta - mg\\sin\\theta = \\pm F\\). For slip UP (friction down slope): \\(P_1\\cos\\theta = mg\\sin\\theta + F_{\\max}\\). \\(0.8P_1 = 29.4 + 19.6 + 0.3P_1\\). \\(0.5P_1 = 49\\). \\(P_1 = 98\\) N. For slip DOWN (friction up slope): \\(mg\\sin\\theta = P_2\\cos\\theta + F_{\\max}\\). \\(29.4 = 0.8P_2 + 19.6 + 0.3P_2\\). \\(9.8 = 1.1P_2\\). \\(P_2 = \\dfrac{9.8}{1.1} \\approx 8.91\\) N.', diagram: true },
      { q: 'Define the angle of friction \\(\\lambda\\) and show that \\(\\tan\\lambda = \\mu\\). A surface has \\(\\mu = 0.6\\); find \\(\\lambda\\).', marks: 6, tier: 'red', modelAnswer: 'The angle of friction \\(\\lambda\\) is the angle between the normal reaction and the resultant reaction (the combined normal reaction and friction force) when friction is at its maximum. At limiting equilibrium, friction \\(F = \\mu R\\). The resultant reaction makes angle \\(\\lambda\\) with the normal where \\(\\tan\\lambda = \\dfrac{F}{R} = \\dfrac{\\mu R}{R} = \\mu\\). Therefore \\(\\tan\\lambda = \\mu\\). With \\(\\mu = 0.6\\): \\(\\lambda = \\arctan(0.6) \\approx 31.0°\\).' },
      { q: 'Two particles A (mass 3 kg) and B (mass 5 kg) are connected by a light string passing over a smooth pulley at the top of a rough inclined plane (angle \\(35°\\), \\(\\mu = 0.3\\)). Both particles are on the slope. Find the acceleration. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: 'Both on the slope. Component of A down slope: \\(3g\\sin 35° \\approx 3 \\times 9.8 \\times 0.5736 \\approx 16.86\\) N. Component of B down slope: \\(5g\\sin 35° \\approx 5 \\times 9.8 \\times 0.5736 \\approx 28.11\\) N. B is heavier so B slides down, A goes up. Friction on B (up slope, opposing B going down): \\(F_B = 0.3 \\times 5 \\times 9.8 \\times \\cos 35° \\approx 0.3 \\times 49 \\times 0.8192 \\approx 12.04\\) N. Friction on A (down slope, opposing A going up): \\(F_A = 0.3 \\times 3 \\times 9.8 \\times \\cos 35° \\approx 0.3 \\times 29.4 \\times 0.8192 \\approx 7.23\\) N. Net force: \\(28.11 - 16.86 - 12.04 - 7.23 = -8.02\\) N — this is negative, suggesting B does not slide down. Check if system is in equilibrium: required friction = \\(28.11 - 16.86 = 11.25\\) N total. Max available \\(= 12.04 + 7.23 = 19.27\\) N > 11.25 N, so system is in equilibrium. \\(a = 0\\).', diagram: true },
      { q: 'A particle of mass 8 kg rests on a rough horizontal floor (\\(\\mu = 0.4\\)). A force P at angle \\(\\alpha\\) above the horizontal is applied. Find the angle \\(\\alpha\\) that minimises the force P needed to slide the particle. (\\(g = 9.8\\) m/s²)', marks: 7, tier: 'red', modelAnswer: 'Perpendicular: \\(R = mg - P\\sin\\alpha\\). At limiting equilibrium: \\(P\\cos\\alpha = \\mu R = \\mu(mg - P\\sin\\alpha)\\). \\(P\\cos\\alpha + \\mu P\\sin\\alpha = \\mu mg\\). \\(P = \\dfrac{\\mu mg}{\\cos\\alpha + \\mu\\sin\\alpha}\\). To minimise P, maximise the denominator \\(f(\\alpha) = \\cos\\alpha + \\mu\\sin\\alpha\\). Differentiate: \\(f\'(\\alpha) = -\\sin\\alpha + \\mu\\cos\\alpha = 0\\), so \\(\\tan\\alpha = \\mu = 0.4\\). Therefore \\(\\alpha = \\arctan(0.4) \\approx 21.8°\\). Note: this angle equals the angle of friction \\(\\lambda\\). Minimum force: \\(P_{\\min} = \\dfrac{0.4 \\times 8 \\times 9.8}{\\sqrt{1 + \\mu^2}} = \\dfrac{31.36}{\\sqrt{1.16}} \\approx \\dfrac{31.36}{1.0770} \\approx 29.1\\) N.' },
      { q: 'A particle of mass 10 kg sits on a rough inclined plane (angle \\(25°\\), \\(\\mu = 0.55\\)) and a force \\(Q\\) N is applied perpendicular to the slope (pushing the particle INTO the slope). Find the minimum value of \\(Q\\) to prevent the particle from sliding down. (\\(g = 9.8\\) m/s²)', marks: 7, tier: 'red', modelAnswer: 'Normal reaction: \\(R = mg\\cos 25° + Q\\). Friction (up slope, preventing slide down): \\(F = \\mu R = 0.55(mg\\cos 25° + Q)\\). For equilibrium: \\(F \\geq mg\\sin 25°\\). \\(0.55(mg\\cos 25° + Q) \\geq mg\\sin 25°\\). \\(mg\\cos 25° \\approx 10 \\times 9.8 \\times 0.9063 = 88.82\\) N. \\(mg\\sin 25° \\approx 10 \\times 9.8 \\times 0.4226 = 41.41\\) N. \\(0.55(88.82 + Q) \\geq 41.41\\). \\(48.85 + 0.55Q \\geq 41.41\\). \\(0.55Q \\geq -7.44\\). Since this is negative, \\(Q \\geq -13.5\\) N. Since \\(Q\\) must be non-negative (force presses into slope), \\(Q_{\\min} = 0\\) — the particle does not slide without any additional force. The friction alone (\\(48.85\\) N) exceeds the gravitational component down the slope (\\(41.41\\) N).', diagram: true },
      { q: 'A particle of mass 7 kg is on a rough slope (angle \\(50°\\), \\(\\mu = 0.3\\)). It is pulled up by a rope parallel to the slope with tension \\(T_1\\) and also by a rope parallel to the slope pulling it down. Determine \\(T_1\\) for the particle to move up at constant speed, and \\(T_2\\) for the particle to move down at constant speed. (\\(g = 9.8\\) m/s²)', marks: 8, tier: 'red', modelAnswer: '\\(mg\\sin 50° = 7 \\times 9.8 \\times \\sin 50° \\approx 68.6 \\times 0.7660 \\approx 52.55\\) N. \\(R = 7 \\times 9.8 \\times \\cos 50° \\approx 68.6 \\times 0.6428 \\approx 44.09\\) N. Friction \\(= \\mu R = 0.3 \\times 44.09 \\approx 13.23\\) N. Moving UP at constant speed: tension \\(T_1\\) acts up slope; friction acts DOWN slope; gravity acts DOWN slope. \\(T_1 = mg\\sin 50° + F = 52.55 + 13.23 = 65.78\\) N. Moving DOWN at constant speed: tension \\(T_2\\) acts down slope; friction acts UP slope; gravity acts DOWN slope. Net force down = 0: \\(mg\\sin 50° + T_2 - F = 0\\), so \\(T_2 = F - mg\\sin 50° = 13.23 - 52.55 = -39.32\\) N. Negative means the rope would need to act UP the slope to allow constant speed descent; magnitude of tension required up the slope \\(= 39.32\\) N. (The particle would accelerate down without any rope, as \\(mg\\sin 50° > F\\).)' },
    ],
  },

};
